import { Component, OnInit, OnDestroy, inject, ChangeDetectorRef } from '@angular/core';
import { FormBuilder, FormGroup } from '@angular/forms';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule } from '@angular/forms';
import { Router } from '@angular/router';
import { SupabaseService } from '../../services/Base/supabase.service';
import { AuthService } from '../../services/Base/auth.service';
import { filter, Subject, switchMap, takeUntil } from 'rxjs';
import { Restaurant } from '../../models';
import { LucideAngularModule } from 'lucide-angular';
import { PushNotificationService } from '../../services/push-notification.service';

@Component({
  selector: 'app-settings-customer',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, LucideAngularModule],
  templateUrl: './settings-customer.html',
  styleUrls: ['./settings-customer.css']
})
export class SettingsCustomer implements OnInit, OnDestroy {

  public pushService = inject(PushNotificationService);
  private cdr = inject(ChangeDetectorRef);

  settingsForm!: FormGroup;
  loading = false;

  staffRestaurants: any[] = [];
  ownedRestaurants: any[] = [];
  userProfile: any = null;
  restaurant: any = null;

  // NOTIFICHE
  pushPermission: NotificationPermission | 'unsupported' = 'default';
  hasActivePush = false;
  pushLoading = false;

  // Danger zone
  showDeactivateUserConfirm = false;
  showDeleteUserConfirm = false;
  accountActionLoading = false;
  accountActionError = '';

  private destroy$ = new Subject<void>();
  private supabaseClient = inject(SupabaseService).getSupabaseClient();
  private authService = inject(AuthService);
  private router = inject(Router);

  constructor(private fb: FormBuilder) {}

ngOnInit() {
  this.initForm();
  this.setupStaffRestaurantsSubscription();
  this.loadUserProfile();           // per preferenze e is_active
  this.loadOwnedRestaurants();

  // Imposta lo stato iniziale delle notifiche push
  this.pushPermission = this.pushService.isSupported()
    ? Notification.permission
    : 'unsupported';

  // Controlla se l'utente ha già una subscription attiva (dopo che l'utente è disponibile)
  this.authService.currentUser$
    .pipe(
      filter(user => !!user),
      takeUntil(this.destroy$),
      switchMap(() => this.pushService.hasActiveSubscription())
    )
    .subscribe(active => {
      this.hasActivePush = active;
      this.cdr.detectChanges(); // forza aggiornamento vista
    });
}

  ngOnDestroy() {
    this.destroy$.next();
    this.destroy$.complete();
  }

  private initForm() {
    this.settingsForm = this.fb.group({
      email_notifications: [true],
      newsletter: [true],
      is_active: [true]
    });
  }

private async loadUserProfile() {
  this.loading = true;
  try {
    const user = this.authService.currentUserValue;
    if (!user) return;
    const { data, error } = await this.supabaseClient
      .from('users')
      .select('preferences, is_active')
      .eq('id', user.id)
      .single();
    if (error) {
      if (error.code === 'PGRST116') {
        await this.createMinimalProfile(user.id);
        return;
      }
      throw error;
    }
    if (data) {
      this.settingsForm.patchValue({
        email_notifications: data.preferences?.email_notifications ?? true,
        newsletter: data.preferences?.newsletter ?? true,
        is_active: data.is_active ?? true
      });
    }
  } catch (err) {
    console.error('Errore caricamento profilo:', err);
  } finally {
    this.loading = false;
  }
}

  private async createMinimalProfile(userId: string) {
    const user = this.authService.currentUserValue;
    if (!user) return;

    const payload = {
      id: userId,
      email: user.email,
      preferences: {
        email_notifications: true,
        newsletter: true
      },
      is_active: true,
      role: 'customer',
      created_at: new Date().toISOString(),
      updated_at: new Date().toISOString()
    };

    const { error } = await this.supabaseClient
      .from('users')
      .insert(payload);

    if (!error) {
      this.settingsForm.patchValue({
        email_notifications: true,
        newsletter: true,
        is_active: true
      });
    }
  }

  // ────────────────────────────────────────────────
  //          PARTE RISTORANTI – tienila tutta
  // ────────────────────────────────────────────────

  private setupStaffRestaurantsSubscription() {
    this.authService.allStaffRecords$.pipe(takeUntil(this.destroy$)).subscribe(
      async (staffRecords) => {
        if (staffRecords?.length) {
          await this.loadStaffRestaurants(staffRecords);
        } else {
          this.staffRestaurants = [];
        }
      }
    );
  }

  private async loadStaffRestaurants(staffRecords: any[]) {
    this.loading = true;
    try {
      const promises = staffRecords.map(async (record) => {
        const { data, error } = await this.supabaseClient
          .from('restaurants')
          .select('*')
          .eq('id', record.restaurant_id)
          .single();

        if (error) return null;
        return {
          ...data,
          staff_role: record.role,
          staff_permissions: record.permissions,
          staff_invitation_status: record.invitation_status
        };
      });

      const restaurants = await Promise.all(promises);
      this.staffRestaurants = restaurants.filter(Boolean);
    } catch (err) {
      console.error('Errore staff restaurants:', err);
      this.staffRestaurants = [];
    } finally {
      this.loading = false;
    }
  }

private async loadOwnedRestaurants() {
  const user = this.authService.currentUserValue;
  if (!user) return;
  try {
    const { data, error } = await this.supabaseClient
      .from('restaurants')
      .select('*')
      .eq('owner_id', user.id);
    if (error) throw error;
    this.ownedRestaurants = (data || []).map(r => ({
      ...r,
      staff_role: 'owner',
      is_owner: true
    }));
    this.restaurant = this.ownedRestaurants[0] || null; // ← aggiunto
  } catch (err) {
    console.error('Errore owned restaurants:', err);
    this.ownedRestaurants = [];
  }
}

  get allRestaurants(): any[] {
    return [...this.ownedRestaurants, ...this.staffRestaurants];
  }

  isCurrentRestaurant(restaurantId: string): boolean {
    return this.authService.getCurrentRestaurantId() === restaurantId;
  }

  async switchToRestaurant(restaurant: any) {
    this.loading = true;
    try {
      const success = await this.authService.switchRestaurant(restaurant.id);
      if (!success) throw new Error('Switch fallito');

      setTimeout(() => {
        this.router.navigate(['/restaurant/dashboard']);
      }, 400);
    } catch (err: any) {
      console.error(err);
      alert('Errore cambio ristorante: ' + (err.message || 'Errore sconosciuto'));
    } finally {
      this.loading = false;
    }
  }

  // ────────────────────────────────────────────────

  async onSubmit() {
    if (this.settingsForm.invalid) return;
    this.loading = true;

    try {
      const user = this.authService.currentUserValue;
      if (!user) throw new Error('Utente non loggato');

      const values = this.settingsForm.value;

      const updateData = {
        preferences: {
          email_notifications: values.email_notifications,
          newsletter: values.newsletter
        },
        is_active: values.is_active,
        updated_at: new Date().toISOString()
      };

      const { error } = await this.supabaseClient
        .from('users')
        .update(updateData)
        .eq('id', user.id);

      if (error) throw error;

      alert('Impostazioni salvate!');
    } catch (err: any) {
      console.error(err);
      alert('Errore salvataggio: ' + (err.message || 'Errore sconosciuto'));
    } finally {
      this.loading = false;
    }
  }

  resetForm() {
    this.loadUserProfile();
  }

  async confirmDeactivateUser() {
  this.accountActionLoading = true;
  this.accountActionError = '';
  const result = await this.authService.deactivateUserAccount();
  if (result.success) {
    await this.authService.logout();
  } else {
    this.accountActionError = result.error || 'Errore durante la disattivazione';
    this.showDeactivateUserConfirm = false;
  }
  this.accountActionLoading = false;
}

async confirmDeleteUser() {
  this.accountActionLoading = true;
  this.accountActionError = '';
  const result = await this.authService.deleteUserAccount();
  if (!result.success) {
    this.accountActionError = result.error || 'Errore durante la cancellazione';
    this.showDeleteUserConfirm = false;
  }
  this.accountActionLoading = false;
}


async enablePushNotifications() {
  this.pushLoading = true;
  try {
    const success = await this.pushService.requestPermissionAndSubscribe();
    this.hasActivePush = success;
    this.pushPermission = Notification.permission;
  } catch (err) {
    console.error(err);
  } finally {
    this.pushLoading = false;
    this.cdr.detectChanges();
  }
}

async disablePushNotifications() {
  this.pushLoading = true;
  await this.pushService.revokeConsent();
  this.hasActivePush = false;
  this.pushLoading = false;
  this.cdr.detectChanges();
}

get isPushActive(): boolean {
  return this.pushPermission === 'granted' && this.hasActivePush;
}

async togglePush() {
  if (this.pushLoading) return;
  if (this.isPushActive) {
    await this.disablePushNotifications();
  } else {
    await this.enablePushNotifications();
  }
}
}